                    dev.has_tailwind_plugin_hack = if (dev.vm.transpiler.options.serve_plugins) |serve_plugins|
                        for (serve_plugins) |plugin| {
                            if (bun.strings.includes(plugin, "tailwind")) break .empty;
                        } else null
                    else
                        null;

