datatype ParseHexResult = Null | Value(value: int)

predicate IsHexChar(c: char) {
  c == '0' || c == '1' || c == '2' || c == '3' || c == '4' ||
  c == '5' || c == '6' || c == '7' || c == '8' || c == '9' ||
  c == 'a' || c == 'b' || c == 'c' || c == 'd' || c == 'e' || c == 'f' ||
  c == 'A' || c == 'B' || c == 'C' || c == 'D' || c == 'E' || c == 'F'
}

function HexValue(c: char): int
  requires IsHexChar(c)
  ensures 0 <= HexValue(c) < 16
{
  if c == '0' then 0 else if c == '1' then 1 else if c == '2' then 2 else if c == '3' then 3 else
  if c == '4' then 4 else if c == '5' then 5 else if c == '6' then 6 else if c == '7' then 7 else
  if c == '8' then 8 else if c == '9' then 9 else if c == 'a' || c == 'A' then 10 else
  if c == 'b' || c == 'B' then 11 else if c == 'c' || c == 'C' then 12 else
  if c == 'd' || c == 'D' then 13 else if c == 'e' || c == 'E' then 14 else 15
}

predicate ValidHexString(slice: seq<char>) {
  forall i :: 0 <= i < |slice| ==> IsHexChar(slice[i])
}

function HexToBytes(slice: seq<char>): seq<int>
  requires ValidHexString(slice)
  requires |slice| % 2 == 0
  ensures |HexToBytes(slice)| == |slice| / 2
  ensures forall i :: 0 <= i < |HexToBytes(slice)| ==> 0 <= HexToBytes(slice)[i] < 256
  decreases |slice|
{
  if |slice| == 0 then [] else [16 * HexValue(slice[0]) + HexValue(slice[1])] + HexToBytes(slice[2..])
}

// Abstracts Zig `@bitCast(out)`: the integer value is whatever the target
// memory representation of the decoded bytes denotes.
function BitCastBytesToInt(bytes: seq<int>): int
  requires forall i :: 0 <= i < |bytes| ==> 0 <= bytes[i] < 256

function ParseHexToInt(size: nat, slice: seq<char>): ParseHexResult {
  if ValidHexString(slice) && |slice| == 2 * size then
    Value(BitCastBytesToInt(HexToBytes(slice)))
  else
    Null
}

lemma ParseHexValidExactLengthReturnsBitcast(size: nat, slice: seq<char>)
  requires ValidHexString(slice)
  requires |slice| == 2 * size
  ensures ParseHexToInt(size, slice).Value?
  ensures ParseHexToInt(size, slice).value == BitCastBytesToInt(HexToBytes(slice))
{
  assert |slice| % 2 == 0;
  assert ParseHexToInt(size, slice) == Value(BitCastBytesToInt(HexToBytes(slice)));
}

lemma ParseHexBoundaryExactLengthU64Witness(slice: seq<char>)
  requires ValidHexString(slice)
  requires |slice| == 16
  ensures ParseHexToInt(8, slice).Value?
  ensures ParseHexToInt(8, slice).value == BitCastBytesToInt(HexToBytes(slice))
{
  ParseHexValidExactLengthReturnsBitcast(8, slice);
}

lemma ParseHexBoundaryExactLengthOneByteWitness(slice: seq<char>)
  requires ValidHexString(slice)
  requires |slice| == 2
  ensures ParseHexToInt(1, slice).Value?
  ensures ParseHexToInt(1, slice).value == BitCastBytesToInt(HexToBytes(slice))
{
  ParseHexValidExactLengthReturnsBitcast(1, slice);
}

